mapper.select:
SELECT COUNT(1) FROM appointment
WHERE visited_user_id = #{hostId}
AND status IN ('PENDING','FIRST_APPROVED','APPROVED')
AND (
    (start_time < #{endTime} AND end_time > #{startTime})
)

    AND id != #{excludeId}

SELECT COUNT(1) FROM appointment
WHERE status IN ('PENDING','FIRST_APPROVED','APPROVED')
AND (
    (start_time < #{endTime} AND end_time > #{startTime})
)
AND (
    (#{visitorId} IS NOT NULL AND visitor_id = #{visitorId})
    OR (#{visitorIdCard} IS NOT NULL AND #{visitorIdCard} != '' AND visitor_id_card = #{visitorIdCard})
)

    AND id != #{excludeId}

SELECT COUNT(1) FROM appointment
WHERE status IN ('PENDING','FIRST_APPROVED','APPROVED')
AND start_time >= #{dayStart}
AND start_time < #{dayEnd}
AND (
    (#{visitorId} IS NOT NULL AND visitor_id = #{visitorId})
    OR (#{visitorIdCard} IS NOT NULL AND #{visitorIdCard} != '' AND visitor_id_card = #{visitorIdCard})
)
